          "name": "deny-unsafe-or-out-of-scope-github-requests",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source explicitly denies secret exfiltration, raw file export, unbounded codebase dumps, and direct workflow bypass.",
            "capability": "governed denial enforcement",
            "confidence": "high",
            "time_scope": "Whenever a request exceeds the approved capability surface.",
            "actor_context": "Any requester whose ask exceeds the governed repository capability boundary.",
            "business_scope": "Policy enforcement for denied GitHub operations and unsafe data access."
          },
          "category": "safety",
          "narrative": "A requester tries to use the governed GitHub surface for actions outside the approved capability boundary, such as secret access, raw file export, unbounded codebase dumping, or workflow bypass. ANIP rejects the request and does not expose raw backend power through the agent-facing interface.",
          "expected_behavior": [
            "Deny unsafe or out-of-scope requests explicitly.",
            "Do not translate denied asks into raw GitHub API calls.",
            "Preserve the bounded capability surface even when the backend could technically do more.",
            "Return a clear governed stop rather than partial unsafe output.",
            "Capture audit evidence for the denial."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Enforce deny rules at the ANIP capability layer.",
            "Prevent raw tool exposure from bypassing product policy.",
            "Return explicit denial outcomes with audit metadata.",
            "Keep backend_options from becoming an escape hatch for unsafe operations."
          ],
          "participating_services": [
            "GitHub Governance Service"
          ]
        }
      }
    },
    {
      "id": "scenario-e16be887-25d8-437c-a77f-b6f060440b5c",
