            "capability": "github.pr.comment.prepare",
            "confidence": "high",
            "time_scope": "During pull request review or release coordination.",
            "actor_context": "Pull request comment requester operating within an allowlisted repository and approval-governed mutation boundary.",
            "business_scope": "Pull request comment governance for review and release-related communication."
          },
          "category": "orchestration",
          "narrative": "A user wants to add a pull request comment based on review or release context, but the product must avoid direct write access. They provide repository, pull request number, comment purpose, and supporting context. ANIP prepares the comment as a governed preview and stops for approval before any comment is posted to GitHub.",
          "expected_behavior": [
            "Require explicit pull request context before preparing a comment.",
            "Return a preview rather than posting directly.",
            "Stop for approval before any downstream comment mutation.",
            "Return clarification_required if pull request context is missing.",
            "Keep the action bounded to the specified allowlisted repository."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Bind comment preparation to a governed preview capability rather than raw comment APIs.",
            "Enforce approval before posting.",
            "Preserve repository scope, actor context, and audit records.",
            "Prevent direct broad code-hosting tool exposure to the agent."
          ],
          "participating_services": [
            "GitHub Governance Service",
            "native GitHub REST/GraphQL API adapter"
          ]
        }
      }
    },
    {
