            "capability": "github.repo.search_context",
            "confidence": "high",
            "time_scope": "On demand during repository review or delivery planning.",
            "actor_context": "Repository operator seeking read-only repository context within an allowlisted repository.",
            "business_scope": "Repository context access for issue and pull request discovery under explicit repository scope controls."
          },
          "category": "safety",
          "narrative": "A repository operator needs repository context to understand current issues or pull requests. They provide owner, repository, and query within an allowed repository. ANIP executes a bounded search and returns summaries rather than raw repository export, preserving repository-scope controls and auditability.",
          "expected_behavior": [
            "Require explicit owner, repo, and query before execution.",
            "Return bounded issue and pull request summaries only.",
            "Restrict results to allowlisted repositories.",
            "Do not expose raw repository export, secret access, or unbounded codebase dumps.",
            "Record audit metadata for the governed search request."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Enforce repository allowlists before backend execution.",
            "Map the governed search capability to bounded GitHub REST or GraphQL operations.",
            "Return explicit clarification_required when repository context is missing.",
            "Preserve audit records for request scope and outcome."
          ],
          "participating_services": [
            "GitHub Governance Service",
            "native GitHub REST/GraphQL API adapter"
          ]
        }
      }
    },
    {
      "id": "scenario-2c8d2b63-3d29-4a62-a928-6690c6e6029a",
      "title": "Stop for clarification when repository, pull request, workflow, or range context is missing",
      "data": {
        "scenario": {
          "name": "stop-for-clarification-when-required-github-context-is-missing",
          "context": {
            "source": "assistant_product_design_bundle",
            "rationale": "The source explicitly states that missing repo, pull request, workflow, or range context returns clarification_required.",
            "capability": "cross-capability clarification behavior",
            "confidence": "high",
            "time_scope": "Any time a request lacks required repository-specific inputs.",
            "actor_context": "Any authorized requester whose intent is valid but whose request is incomplete.",
            "business_scope": "Safe handling of incomplete requests across governed GitHub capabilities."
          },
          "category": "safety",
          "narrative": "A user requests a repository search, issue preparation, pull request comment, workflow dispatch, or release-note draft without enough repository-specific context to execute safely. ANIP does not infer missing repository, pull request, workflow, or range values. Instead, it returns clarification_required and asks for the minimum missing information needed to proceed.",
          "expected_behavior": [
            "Do not guess missing repository-specific values.",
            "Return clarification_required explicitly.",
            "Ask only for the minimum missing inputs needed to continue.",
            "Avoid backend execution until required context is supplied.",
            "Apply the same clarification posture consistently across governed capabilities."
          ],
          "orchestration_steps": [],
          "expected_anip_support": [
            "Provide explicit clarification outcomes in the contract.",
            "Standardize missing-context handling across capabilities.",
            "Prevent silent defaults that could widen repository scope or trigger the wrong operation.",
            "Audit the clarification stop and the missing fields."
